function MedErrors(a){switch(a){case-1:alert("Medical Lib : File not Found");break;case-2:alert("Medical Lib : nnot Load File");break;case-3:alert("Medical Lib : No Lines Found");break;case-4:alert("Medical Lib : Image not Loaded");break;case-5:alert("Medical Lib : Invalid Field");break;case-6:alert("Medical Lib : No Data");break;case-7:alert("Medical Lib : Last Data");break;case-8:alert("Medical Lib : Next Data Exists");break;default:alert("Medical Lib : Error - "+a)}}